import time

class ResponseCacheMiddleware:
    def __init__(self, app, cache_timeout=60):
        """
        WSGI middleware that caches responses for GET requests.

        Args:
            app: The WSGI application to wrap.
            cache_timeout (int): The number of seconds to cache responses.
        """
        self.app = app
        self.cache_timeout = cache_timeout
        # Cache structure: {cache_key: {'status': str, 'headers': list, 'body': bytes, 'timestamp': float}}
        self.cache = {}

    def __call__(self, environ, start_response):
        method = environ.get('REQUEST_METHOD', 'GET')
        path = environ.get('PATH_INFO', '/')
        query = environ.get('QUERY_STRING', '')

        if method != 'GET':
            return self.app(environ, start_response)

        cache_key = f"{path}?{query}"

        cached_item = self.cache.get(cache_key)
        if cached_item:
            if (time.time() - cached_item['timestamp']) < self.cache_timeout:
                start_response(cached_item['status'], cached_item['headers'])
                return [cached_item['body']]
            else:
                del self.cache[cache_key]

        response_status = None
        response_headers = []
        response_body_parts = []

        def capture_start_response(status, headers, exc_info=None):
            nonlocal response_status, response_headers
            response_status = status
            response_headers = headers
            return lambda body_chunk: None

        app_iterator = self.app(environ, capture_start_response)

        try:
            for data in app_iterator:
                if isinstance(data, str):
                    data = data.encode('utf-8')
                response_body_parts.append(data)
        finally:
            if hasattr(app_iterator, 'close'):
                app_iterator.close()

        full_response_body = b''.join(response_body_parts)

        if response_status and response_status.startswith('200 '):
            self.cache[cache_key] = {
                'status': response_status,
                'headers': response_headers,
                'body': full_response_body,
                'timestamp': time.time()
            }

        start_response(response_status, response_headers)
        return [full_response_body]
